import{_ as n,C as i,o,c as r,a2 as t,E as s}from"./chunks/framework.BWHo9ZVz.js";const y=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"part-5/ch22-what-is-concurrency.md","filePath":"part-5/ch22-what-is-concurrency.md"}'),l={name:"part-5/ch22-what-is-concurrency.md"};function c(d,e,h,p,g,u){const a=i("VideoPlayer");return o(),r("div",null,[e[0]||(e[0]=t('<h2 id="chapter-22-what-is-concurrency" tabindex="-1">Chapter 22: What is Concurrency <a class="header-anchor" href="#chapter-22-what-is-concurrency" aria-label="Permalink to &quot;Chapter 22: What is Concurrency&quot;">​</a></h2><div class="slide-visualization-box no-print"><details><summary>📊 Slide Reference: <code>/slides/go-22-what-is-concurrency-slides.pdf</code></summary><div class="slide-iframe-container"><iframe src="/GO-Lang-Matt/slides/go-22-what-is-concurrency-slides.pdf" width="100%" height="450px" style="border:none;"></iframe></div></details></div>',2)),s(a,{videoId:"A3R-4ZYBqvE",chapter:"22"}),e[1]||(e[1]=t(`<p>Concurrency is one of Go&#39;s most celebrated features. However, before writing concurrent code, we must clearly define what concurrency is, how it differs from parallelism, and the unique challenges it introduces.</p><h3 id="concurrency-vs-parallelism" tabindex="-1">Concurrency vs. Parallelism <a class="header-anchor" href="#concurrency-vs-parallelism" aria-label="Permalink to &quot;Concurrency vs. Parallelism&quot;">​</a></h3><p>Many programmers conflate concurrency and parallelism, but they are distinct concepts:</p><ul><li><strong>Concurrency</strong> is about <strong>structure</strong>. It is the composition of independently executing processes. A program is concurrent if it is divided into discrete components that <em>can</em> run out of order or in a non-deterministic sequence without affecting the final result.</li><li><strong>Parallelism</strong> is about <strong>execution</strong>. It is the simultaneous execution of multiple entities at the exact same physical instant.</li></ul><p>As Rob Pike famously stated:</p><blockquote><p><em>&quot;Concurrency is about dealing with lots of things at once. Parallelism is about doing lots of things at once.&quot;</em></p></blockquote><h4 id="the-road-bridge-analogy" tabindex="-1">The Road Bridge Analogy <a class="header-anchor" href="#the-road-bridge-analogy" aria-label="Permalink to &quot;The Road Bridge Analogy&quot;">​</a></h4><p>To visualize this, imagine a two-lane road:</p><ol><li><strong>Parallelism (Independent Execution):</strong> A highway with a northbound lane and a southbound lane. Cars in both directions travel at the same time without interfering with each other.</li><li><strong>Concurrency with Shared State (Stoplight Control):</strong> The road encounters a narrow one-way bridge. To prevent a head-on collision (a data race), we must install stoplights at both ends. The stoplights enforce safety, but traffic must now back up (synchronization overhead), reducing performance.</li></ol><p>Concurrency is a property of the software design; parallelism is a property of the runtime hardware. A concurrent program can run in parallel on a multi-core processor, but it can also run sequentially (via time-slicing) on a single-core processor.</p><h3 id="partial-ordering-non-determinism" tabindex="-1">Partial Ordering &amp; Non-Determinism <a class="header-anchor" href="#partial-ordering-non-determinism" aria-label="Permalink to &quot;Partial Ordering &amp; Non-Determinism&quot;">​</a></h3><p>In sequential programming, we have a <strong>total ordering</strong>: step A executes, then step B, then step C. In concurrent programming, we have a <strong>partial ordering</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Step 1]</span></span>
<span class="line"><span>   /\\</span></span>
<span class="line"><span>  /  \\</span></span>
<span class="line"><span>[2A] [3A]</span></span>
<span class="line"><span> |    |</span></span>
<span class="line"><span>[2B] [3B]</span></span>
<span class="line"><span>  \\  /</span></span>
<span class="line"><span>   \\/</span></span>
<span class="line"><span>[Step 4]</span></span></code></pre></div><p>Step 1 must happen first, and Step 4 must happen last. However, there is no defined relationship between the <code>2</code> branch and the <code>3</code> branch. The runtime scheduler can execute them in several valid sequences:</p><ul><li><code>1 -&gt; 2A -&gt; 2B -&gt; 3A -&gt; 3B -&gt; 4</code></li><li><code>1 -&gt; 3A -&gt; 3B -&gt; 2A -&gt; 2B -&gt; 4</code></li><li><code>1 -&gt; 2A -&gt; 3A -&gt; 2B -&gt; 3B -&gt; 4</code></li></ul><p>Because of this partial ordering, execution is <strong>non-deterministic</strong>. The scheduler&#39;s choices depend on CPU load, thread sleep states, and OS thread scheduling.</p><h3 id="the-race-condition" tabindex="-1">The Race Condition <a class="header-anchor" href="#the-race-condition" aria-label="Permalink to &quot;The Race Condition&quot;">​</a></h3><p>A <strong>race condition</strong> occurs when the program&#39;s correctness depends on the non-deterministic order of execution. If any of the possible scheduling outcomes produces an incorrect result, the program has a bug—even if it runs correctly 99% of the time.</p><h4 id="read-modify-write-cycles" tabindex="-1">Read-Modify-Write Cycles <a class="header-anchor" href="#read-modify-write-cycles" aria-label="Permalink to &quot;Read-Modify-Write Cycles&quot;">​</a></h4><p>The classic example of a race condition is a concurrent counter increment (<code>x++</code>). At the hardware level, this is not a single instruction; it is a <strong>read-modify-write cycle</strong>:</p><ol><li><strong>Read:</strong> Copy the value of <code>x</code> from memory into a CPU register.</li><li><strong>Modify:</strong> Add <code>1</code> to the register.</li><li><strong>Write:</strong> Copy the register value back to memory.</li></ol><p>If two concurrent threads attempt to increment <code>x</code> (initial value: 100) simultaneously without synchronization, their operations may interleave:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Time</th><th style="text-align:left;">Thread A</th><th style="text-align:left;">Thread B</th><th style="text-align:left;">Memory Value</th></tr></thead><tbody><tr><td style="text-align:left;">$T_1$</td><td style="text-align:left;">Reads <code>x</code> (100)</td><td style="text-align:left;"></td><td style="text-align:left;">100</td></tr><tr><td style="text-align:left;">$T_2$</td><td style="text-align:left;"></td><td style="text-align:left;">Reads <code>x</code> (100)</td><td style="text-align:left;">100</td></tr><tr><td style="text-align:left;">$T_3$</td><td style="text-align:left;">Increments to 101</td><td style="text-align:left;"></td><td style="text-align:left;">100</td></tr><tr><td style="text-align:left;">$T_4$</td><td style="text-align:left;">Writes <code>x</code> = 101</td><td style="text-align:left;"></td><td style="text-align:left;">101</td></tr><tr><td style="text-align:left;">$T_5$</td><td style="text-align:left;"></td><td style="text-align:left;">Increments to 101</td><td style="text-align:left;">101</td></tr><tr><td style="text-align:left;">$T_6$</td><td style="text-align:left;"></td><td style="text-align:left;">Writes <code>x</code> = 101</td><td style="text-align:left;"><strong>101</strong></td></tr></tbody></table><p>Two increments occurred, but the final value is 101. One increment evaporated because the read-modify-write cycle was divided.</p><h3 id="solving-race-conditions" tabindex="-1">Solving Race Conditions <a class="header-anchor" href="#solving-race-conditions" aria-label="Permalink to &quot;Solving Race Conditions&quot;">​</a></h3><p>To prevent race conditions, we must make critical sections <strong>atomic</strong> (indivisible). We have four primary design strategies:</p><ol><li><strong>Do not share state:</strong> If data is local to a single thread, it cannot have a race condition.</li><li><strong>Share state, but make it read-only:</strong> Concurrent reads are always safe.</li><li><strong>Impose a total order:</strong> Restrict concurrency so that operations must run sequentially.</li><li><strong>Use synchronization primitives:</strong> Coordinate access using tools like channels or mutual exclusion locks (mutexes) to protect read-modify-write cycles.</li></ol><hr>`,28))])}const f=n(l,[["render",c]]);export{y as __pageData,f as default};
